import sys

def mat_mult(A, B, mod):
    n = len(A)
    m = len(B)
    p = len(B[0])
    C = [[0] * p for _ in range(n)]
    for i in range(n):
        for k in range(m):
            if A[i][k] == 0:
                continue
            for j in range(p):
                C[i][j] = (C[i][j] + A[i][k] * B[k][j]) % mod
    return C

def mat_pow(matrix, power, mod):
    n = len(matrix)
    result = [[1 if i == j else 0 for j in range(n)] for i in range(n)]
    base = matrix
    while power:
        if power & 1:
            result = mat_mult(result, base, mod)
        base = mat_mult(base, base, mod)
        power //= 2
    return result

def solve():
    L, a, b, M = map(int, sys.stdin.readline().split())
    res = 0
    cur = a
    left = L
    for d in range(1, 19):
        low = 10**(d-1)
        high = 10**d - 1
        if cur > high:
            continue
        if cur + b * (left - 1) < low:
            break
        if cur < low:
            steps = (low - cur + b - 1) // b
            if steps >= left:
                break
            cur += steps * b
            left -= steps
            if left <= 0:
                break
        end_val = min(high, cur + b * (left - 1))
        count = (end_val - cur) // b + 1
        mat = [
            [pow(10, d, M), 1, 0],
            [0, 1, b % M],
            [0, 0, 1]
        ]
        exp_mat = mat_pow(mat, count, M)
        res = (res * exp_mat[0][0] + exp_mat[0][1] * cur + exp_mat[0][2]) % M
        cur += b * count
        left -= count
        if left <= 0:
            break
    print(res % M)

